791: 			task->tk_flags |= RPC_TASK_KILLED;
792: 			rpc_exit(task, -ERESTARTSYS);
793: 		}
794: 		dprintk("RPC: %5u sync task resuming\n", task->tk_pid);
795: 	}
796: 
797: 	dprintk("RPC: %5u return %d, status %d\n", task->tk_pid, status,
798: 			task->tk_status);
